import { Event, PlayerPosition, PlayerLiveStats, TeamMatchStats, RallyEntry, Fundamental } from '../types';
import { computeVolleyRating } from './ratingSystem'; // se serve in futuro

export function aggregatePlayerStats(events: Event[], matchId: string): Record<string, PlayerLiveStats> {
  const statsByPlayer: Record<string, PlayerLiveStats> = {};

  const ensure = (playerId: string): PlayerLiveStats => {
    if (!statsByPlayer[playerId]) {
      statsByPlayer[playerId] = {
        playerId,
        matchId,
        attacks: 0,
        attackPoints: 0,
        attackErrors: 0,
        attackBlocked: 0,
        serves: 0,
        aces: 0,
        serveErrors: 0,
        receptions: 0,
        perfectReceptions: 0,
        positiveReceptions: 0,
        negativeReceptions: 0,
        acesConceded: 0,
        blocks: 0,
        blockPoints: 0,
        blockTouches: 0,
        blockErrors: 0,
        digs: 0,
        digErrors: 0,
      };
    }
    return statsByPlayer[playerId];
  };

  for (const ev of events) {
    const s = ensure(ev.playerId);

    switch (ev.fundamental) {
      case 'attack':
        s.attacks++;
        if (ev.outcomeCode === 'attack_point') s.attackPoints++;
        if (ev.outcomeCode === 'attack_error') s.attackErrors++;
        if (ev.outcomeCode === 'attack_blocked') s.attackBlocked++;
        break;

      case 'serve':
        s.serves++;
        if (ev.outcomeCode === 'serve_ace') s.aces++;
        if (ev.outcomeCode === 'serve_error') s.serveErrors++;
        break;

      case 'reception':
        s.receptions++;
        if (ev.outcomeCode === 'reception_perfect') s.perfectReceptions++;
        if (ev.outcomeCode === 'reception_positive') s.positiveReceptions++;
        if (ev.outcomeCode === 'reception_negative') s.negativeReceptions++;
        if (ev.outcomeCode === 'reception_ace_conceded') s.acesConceded++;
        break;

      case 'block':
        s.blocks++;
        if (ev.outcomeCode === 'block_point') s.blockPoints++;
        if (ev.outcomeCode === 'block_touch') s.blockTouches++;
        if (ev.outcomeCode === 'block_late_miss') s.blockErrors++;
        break;

      case 'defense':
        if (ev.outcomeCode === 'defense_great' || ev.outcomeCode === 'defense_ok') {
          s.digs++;
        }
        if (ev.outcomeCode === 'defense_error') {
          s.digErrors++;
        }
        break;

      default:
        break;
    }
  }

  return statsByPlayer;
}

export function aggregateTeamStats(events: Event[], matchId: string, teamId: string): TeamMatchStats {
  let totalPoints = 0;
  let pointsFromServe = 0;
  let pointsFromReception = 0;
  let pointsFromBlock = 0;
  let pointsFromAttack = 0;
  let aces = 0;
  let serveErrors = 0;
  let receptionErrors = 0;
  let attackErrors = 0;
  let blockErrors = 0;

  for (const ev of events) {
    if (ev.teamId !== teamId) continue;

    if (ev.fundamental === 'serve') {
      if (ev.outcomeCode === 'serve_ace') {
        totalPoints++;
        pointsFromServe++;
        aces++;
      }
      if (ev.outcomeCode === 'serve_error') {
        serveErrors++;
      }
    }

    if (ev.fundamental === 'attack') {
      if (ev.outcomeCode === 'attack_point') {
        totalPoints++;
        pointsFromAttack++;
      }
      if (ev.outcomeCode === 'attack_error' || ev.outcomeCode === 'attack_blocked') {
        attackErrors++;
      }
    }

    if (ev.fundamental === 'reception') {
      if (ev.outcomeCode === 'reception_negative' || ev.outcomeCode === 'reception_ace_conceded') {
        receptionErrors++;
      }
      // punti "da side-out" li semplifichiamo come punti totali già contati da altri fondamentali
    }

    if (ev.fundamental === 'block') {
      if (ev.outcomeCode === 'block_point') {
        totalPoints++;
        pointsFromBlock++;
      }
      if (ev.outcomeCode === 'block_late_miss') {
        blockErrors++;
      }
    }
  }

  return {
    matchId,
    teamId,
    totalPoints,
    pointsFromServe,
    pointsFromReception,
    pointsFromBlock,
    pointsFromAttack,
    aces,
    serveErrors,
    receptionErrors,
    attackErrors,
    blockErrors,
  };
}

/**
 * Costruisce la timeline dei rally per un set, partendo da events già ordinati
 * e da un contesto di punteggio.
 */
export function buildRallyTimeline(
  events: Event[],
  matchId: string,
  options: {
    startingSetNumber: number;
    teamId: string;
    scoreByPoint: (ev: Event) => { scoringSide: 'us' | 'them' } | null;
  }
): RallyEntry[] {
  const timeline: RallyEntry[] = [];
  let currentSet = options.startingSetNumber;
  let teamPoints = 0;
  let oppPoints = 0;
  let sequence = 0;

  for (const ev of events) {
    const scoring = options.scoreByPoint(ev);
    if (!scoring) continue;

    if (scoring.scoringSide === 'us') {
      teamPoints++;
    } else {
      oppPoints++;
    }

    sequence++;

    timeline.push({
      id: `${matchId}-${currentSet}-${sequence}`,
      setNumber: currentSet,
      sequence,
      teamPointsAfter: teamPoints,
      opponentPointsAfter: oppPoints,
      scoringSide: scoring.scoringSide,
      scoringPlayerId: ev.playerId,
      fundamental: ev.fundamental,
      outcomeCode: ev.outcomeCode,
    });
  }

  return timeline;
}
La funzione scoreByPoint la useremo nella pagina di scouting per decidere se un evento è un punto nostro o loro (puoi basarti sul rotationImpact/outcomeCode che hai già).

