const recomputeDerivedData = (updatedEvents: Event[]) => {
  if (!lineup) return;
  const ourTeamId = lineup.teamId ?? teamId; // adatta in base a come tieni il teamId

  // Statistiche live per giocatore
  const playerStats = aggregatePlayerStats(updatedEvents, matchId);
  setLivePlayerStats(playerStats);

  // Statistiche di squadra
  const teamStats = aggregateTeamStats(updatedEvents, matchId, ourTeamId);
  setTeamMatchStats(teamStats);

  // Timeline dei punti
  const timeline = buildRallyTimeline(updatedEvents, matchId, {
    startingSetNumber: currentSet,
    teamId: ourTeamId,
    scoreByPoint: (ev: Event) => {
      // se usi rotationImpact nella logica di outcomeConfig, puoi ricostruirlo qui
      // per semplicità usa: outcomeCode "point" dell'attacco/muro/ace = punto nostro,
      // errori nostri = punto loro
      if (ev.fundamental === 'attack' && ev.outcomeCode === 'attack_point') {
        return { scoringSide: 'us' };
      }
      if (ev.fundamental === 'serve' && ev.outcomeCode === 'serve_ace') {
        return { scoringSide: 'us' };
      }
      if (ev.fundamental === 'block' && ev.outcomeCode === 'block_point') {
        return { scoringSide: 'us' };
      }
      // errori nostri che generano punto avversario
      if (ev.fundamental === 'attack' && (ev.outcomeCode === 'attack_error' || ev.outcomeCode === 'attack_blocked')) {
        return { scoringSide: 'them' };
      }
      if (ev.fundamental === 'serve' && ev.outcomeCode === 'serve_error') {
        return { scoringSide: 'them' };
      }
      if (ev.fundamental === 'reception' && ev.outcomeCode === 'reception_ace_conceded') {
        return { scoringSide: 'them' };
      }
      // altrimenti non cambia punteggio
      return null;
    },
  });
  setRallyTimeline(timeline);
};
