const rotateLineupLogic = (currentLineup: MatchLineup): MatchLineup => {
    const nextPosMap: Record<number, CourtPosition> = {
        1: 6, 6: 5, 5: 4, 4: 3, 3: 2, 2: 1
    };
    const nextOnCourt = currentLineup.onCourt.map(slot => ({
        ...slot,
        position: nextPosMap[slot.position]
    }));
    return {
        ...currentLineup,
        onCourt: nextOnCourt,
        rotationIndex: currentLineup.rotationIndex + 1
    };
};

const isSetOver = (setNumber: number, teamPts: number, oppPts: number): { finished: boolean; winner: 'us' | 'them' | null } => {
  const target = setNumber === 5 ? 15 : 25;
  if (teamPts >= target || oppPts >= target) {
    const diff = Math.abs(teamPts - oppPts);
    if (diff >= 2) {
      if (teamPts > oppPts) return { finished: true, winner: 'us' };
      if (oppPts > teamPts) return { finished: true, winner: 'them' };
    }
  }
  return { finished: false, winner: null };
};

