      { code: 'attack_defended',label: 'Difeso',   symbol: '0',  rotationImpact: 'neutral' },
    ],
  },
  reception: {
    label: 'Ricezione',
    outcomes: [
      { code: 'reception_perfect',         label: 'Perfetta', symbol: '++', rotationImpact: 'neutral' },
      { code: 'reception_positive',        label: 'Positiva', symbol: '+',  rotationImpact: 'neutral' },
      { code: 'reception_negative',        label: 'Negativa', symbol: '-',  rotationImpact: 'point_for_them' },
      { code: 'reception_ace_conceded',    label: 'Ace subito', symbol: '--', rotationImpact: 'point_for_them' },
    ],
  },
  serve: {
    label: 'Battuta',
    outcomes: [
      { code: 'serve_ace',          label: 'Ace',             symbol: '++', rotationImpact: 'point_for_us' },
      { code: 'serve_good_pressure',label: 'Forzata',         symbol: '+',  rotationImpact: 'point_for_us' },
      { code: 'serve_in_play',      label: 'In gioco',        symbol: '0',  rotationImpact: 'neutral' },
      { code: 'serve_error',        label: 'Errore',          symbol: '--', rotationImpact: 'point_for_them' },
    ],
  },
  block: {
    label: 'Muro',
    outcomes: [
      { code: 'block_point',   label: 'Muro punto', symbol: '++', rotationImpact: 'point_for_us' },
      { code: 'block_touch',   label: 'Tocco',      symbol: '+',  rotationImpact: 'neutral' },
      { code: 'block_late_miss', label: 'Fuori tempo', symbol: '-', rotationImpact: 'point_for_them' },
    ],
  },
  defense: {
    label: 'Difesa',
    outcomes: [
      { code: 'defense_great', label: 'Difesa top', symbol: '+', rotationImpact: 'neutral' },
      { code: 'defense_ok',    label: 'Difesa ok',  symbol: '0', rotationImpact: 'neutral' },
      { code: 'defense_error', label: 'Errore',     symbol: '-', rotationImpact: 'point_for_them' },
    ],
  },
  error_other: {
    label: 'Errori',
    outcomes: [
      { code: 'net_fault',      label: 'Fallo rete',      symbol: '-',  rotationImpact: 'point_for_them' },
      { code: 'rotation_fault', label: 'Fallo rotazione', symbol: '--', rotationImpact: 'point_for_them' },
      { code: 'card_yellow',    label: 'Giallo',          symbol: 'Y',  rotationImpact: 'neutral' },
      { code: 'card_red',       label: 'Rosso',           symbol: 'R',  rotationImpact: 'card_red' },
    ],
  },
};

// --- HELPERS ---

const getRoleInitial = (position: PlayerPosition): string => {
  switch (position) {
    case PlayerPosition.SETTER: return 'S';
    case PlayerPosition.OPPOSITE: return 'O';
    case PlayerPosition.OUTSIDE_HITTER: return 'OH';
    case PlayerPosition.MIDDLE_BLOCKER: return 'MB';
    case PlayerPosition.LIBERO: return 'L';
    default: return '?';
  }
};

const getOutcomeColor = (code: OutcomeCode) => {
    if (code.includes('point') || code.includes('ace') || code.includes('perfect') || code.includes('great')) return 'bg-lime text-black border-black';
    if (code.includes('error') || code.includes('fault') || code.includes('conceded')) return 'bg-terracotta text-cream border-black';
    return 'bg-cream-dark text-black border-black';
};

const rotateLineupLogic = (currentLineup: MatchLineup): MatchLineup => {
    const nextPosMap: Record<number, CourtPosition> = {
        1: 6, 6: 5, 5: 4, 4: 3, 3: 2, 2: 1
    };
    const nextOnCourt = currentLineup.onCourt.map(slot => ({
        ...slot,
        position: nextPosMap[slot.position]
    }));
    return {
        ...currentLineup,
        onCourt: nextOnCourt,
        rotationIndex: currentLineup.rotationIndex + 1
    };
};

const isSetOver = (setNumber: number, teamPts: number, oppPts: number): { finished: boolean; winner: 'us' | 'them' | null } => {
  const target = setNumber === 5 ? 15 : 25;
  if (teamPts >= target || oppPts >= target) {
    const diff = Math.abs(teamPts - oppPts);
    if (diff >= 2) {
      if (teamPts > oppPts) return { finished: true, winner: 'us' };
      if (oppPts > teamPts) return { finished: true, winner: 'them' };
    }
  }
  return { finished: false, winner: null };
};

const StatBar: React.FC<{ label: string; value: number; total?: number }> = ({ label, value, total }) => {
  const pct = total && total > 0 ? Math.round((value / total) * 100) : 0;
  return (
    <div>
      <div className="flex justify-between text-xs mb-1 font-bold">
        <span>{label}</span>
        <span>{value} <span className="text-gray-400 font-normal">({pct}%)</span></span>
      </div>
      <div className="h-2 rounded-full bg-white border border-black/10 overflow-hidden">
        <div
          className="h-full bg-teal"
          style={{ width: `${Math.min(pct, 100)}%` }}
        />
      </div>
    </div>
  );
};

export const Scouting: React.FC<ScoutingProps> = ({ matchId, user, onFinished, showToast }) => {
  // Data State
  const [match, setMatch] = useState<Match | null>(null);
  const [players, setPlayers] = useState<Player[]>([]);
  const [lineup, setLineup] = useState<MatchLineup | null>(null);
  const [events, setEvents] = useState<GameEvent[]>([]);

  // UI State
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Stats State
  const [livePlayerStats, setLivePlayerStats] = useState<Record<string, PlayerLiveStats>>({});
  const [teamMatchStats, setTeamMatchStats] = useState<TeamMatchStats | null>(null);
  const [rallyTimeline, setRallyTimeline] = useState<RallyEntry[]>([]);
  const [selectedPlayerForStats, setSelectedPlayerForStats] = useState<Player | null>(null);

  // Game Score State
  const [currentSet, setCurrentSet] = useState(1);
  const [teamPoints, setTeamPoints] = useState(0);
  const [opponentPoints, setOpponentPoints] = useState(0);
  const [setScores, setSetScores] = useState<SetScore[]>([
    { setNumber: 1, teamPoints: 0, opponentPoints: 0, isFinished: false },
  ]);
  const [setsWonUs, setSetsWonUs] = useState<number>(0);
  const [setsWonThem, setSetsWonThem] = useState<number>(0);

  const [rotationIndex, setRotationIndex] = useState(0);
  const [hasRotatedInCurrentRun, setHasRotatedInCurrentRun] = useState<boolean>(false);

  // Interaction State
  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFundamental, setSelectedFundamental] = useState<Fundamental | null>(null);
  const [selectedOutcome, setSelectedOutcome] = useState<OutcomeCode | null>(null);
  const [isImportant, setIsImportant] = useState(false);
  const [isDecisive, setIsDecisive] = useState(false);

  const [isSubMode, setIsSubMode] = useState(false);
  const [selectedBenchPlayerId, setSelectedBenchPlayerId] = useState<string | null>(null);

  // --- DERIVED STATE ---

  const playersById = useMemo(() => {
      const map: Record<string, { position: PlayerPosition, data: Player }> = {};
      players.forEach(p => map[p.id] = { position: p.position, data: p });
      return map;
  }, [players]);

  const liveRatings = useMemo(() => {
      return computeLiveRatingsForMatch(events, playersById);
  }, [events, playersById]);

  // --- HELPERS FOR STATS ---

  const recomputeDerivedData = (updatedEvents: GameEvent[], currentSetNum: number) => {
      if (!match) return;
      const ourTeamId = match.teamId;

      // 1. Player Stats
      const pStats = aggregatePlayerStats(updatedEvents, match.id);
      setLivePlayerStats(pStats);

      // 2. Team Stats
      const tStats = aggregateTeamStats(updatedEvents, match.id, ourTeamId);
      setTeamMatchStats(tStats);

      // 3. Timeline
      const timeline = buildRallyTimeline(updatedEvents, match.id, {
          startingSetNumber: currentSetNum,
          teamId: ourTeamId,
          scoreByPoint: (ev: GameEvent) => {
              const fundConfig = FUNDAMENTAL_CONFIG[ev.fundamental];
              const outcomeConfig = fundConfig?.outcomes.find(o => o.code === ev.outcome);
              if (!outcomeConfig) return null;

              if (outcomeConfig.rotationImpact === 'point_for_us') return { scoringSide: 'us' };
              if (outcomeConfig.rotationImpact === 'point_for_them' || outcomeConfig.rotationImpact === 'card_red') return { scoringSide: 'them' };
              return null;
          }
      });
      setRallyTimeline(timeline);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const init = async () => {
       try {
           const [matches, teamPlayers, initialLineup, existingEvents] = await Promise.all([
               getMatches('t1'),
               getTeamPlayers('t1'),
               getInitialLineupForMatch(matchId),
               getMatchEvents(matchId)
           ]);

           const m = matches.find(x => x.id === matchId);
           setMatch(m || null);
           setPlayers(teamPlayers);
           setLineup(initialLineup);
           setEvents(existingEvents);

           // Initialize derived stats from existing events
           if (m && existingEvents.length > 0) {
               // Determine current set from events
               const maxSet = Math.max(...existingEvents.map(e => e.setNumber));
               setCurrentSet(maxSet);

               // Restore Score (Simplified replay)
               let tp = 0; 
               let op = 0;
               existingEvents.filter(e => e.setNumber === maxSet).forEach(ev => {
                   const fundConfig = FUNDAMENTAL_CONFIG[ev.fundamental];
                   const outcome = fundConfig?.outcomes.find(o => o.code === ev.outcome);
                   if (outcome) {
                       if (outcome.rotationImpact === 'point_for_us') tp++;
                       if (outcome.rotationImpact === 'point_for_them' || outcome.rotationImpact === 'card_red') op++;
                   }
               });
               setTeamPoints(tp);
               setOpponentPoints(op);

               // Calculate stats
               // We need to call this after match state is set, but since it's async closure, 'match' var isn't set yet.
               // We use 'm' and 'm.id'

               const pStats = aggregatePlayerStats(existingEvents, m.id);
               setLivePlayerStats(pStats);

               const tStats = aggregateTeamStats(existingEvents, m.id, m.teamId);
               setTeamMatchStats(tStats);

               // Timeline build
               const timeline = buildRallyTimeline(existingEvents, m.id, {
                    startingSetNumber: maxSet,
                    teamId: m.teamId,
                    scoreByPoint: (ev: GameEvent) => {
                        const fundConfig = FUNDAMENTAL_CONFIG[ev.fundamental];
                        const outcomeConfig = fundConfig?.outcomes.find(o => o.code === ev.outcome);
                        if (!outcomeConfig) return null;
                        if (outcomeConfig.rotationImpact === 'point_for_us') return { scoringSide: 'us' };
                        if (outcomeConfig.rotationImpact === 'point_for_them' || outcomeConfig.rotationImpact === 'card_red') return { scoringSide: 'them' };
                        return null;
                    }
               });
               setRallyTimeline(timeline);
           } else if (m) {
               // Initialize empty stats
               recomputeDerivedData([], 1);
           }

       } catch (error) {
           showToast('error', 'Load Failed', 'Could not load match data.');
       } finally {
           setLoading(false);
       }
    };
    init();
  }, [matchId]); 

  // Auto-context logic
  useEffect(() => {
    const criticalScore = 20;
    const isEndGame = teamPoints >= criticalScore || opponentPoints >= criticalScore;
    setIsImportant(isEndGame);
    const isSetPoint = (teamPoints >= 24 || opponentPoints >= 24) && Math.abs(teamPoints - opponentPoints) >= 1;
    setIsDecisive(isSetPoint);
  }, [teamPoints, opponentPoints]);


  // --- SET MANAGEMENT LOGIC ---

  useEffect(() => {
    const { finished, winner } = isSetOver(currentSet, teamPoints, opponentPoints);

    setSetScores((prev) => {
        const existingIndex = prev.findIndex((s) => s.setNumber === currentSet);
        const updated: SetScore = {
          setNumber: currentSet,
          teamPoints: teamPoints,
          opponentPoints: opponentPoints,
          isFinished: finished,
        };
        if (existingIndex >= 0) {
          const clone = [...prev];
          clone[existingIndex] = updated;
          return clone;
        }
        return [...prev, updated];
    });

    if (finished) {
      showToast('success', `Set ${currentSet} Finished!`, `Winner: ${winner === 'us' ? 'Us' : 'Them'}`);

      if (winner === 'us') setSetsWonUs((prev) => prev + 1);
      else if (winner === 'them') setSetsWonThem((prev) => prev + 1);

      if (currentSet < 5) {
        const nextSetNumber = currentSet + 1;
        setTeamPoints(0);
        setOpponentPoints(0);
        setCurrentSet(nextSetNumber);
        setHasRotatedInCurrentRun(false);

        if (lineup) {
            setLineup(prev => prev ? ({ ...prev, rotationIndex: 0 }) : null);
            setRotationIndex(0);
        }

        setSetScores((prev) => [
            ...prev,
            { setNumber: nextSetNumber, teamPoints: 0, opponentPoints: 0, isFinished: false }
        ]);

        // Reset timeline for new set
        setRallyTimeline([]);
      }
    }
  }, [teamPoints, opponentPoints, currentSet]);


  // --- HANDLERS ---

  const handleManualRotate = async () => {
      if (!lineup) return;
      const nextLineup = rotateLineupLogic(lineup);

      // Update local state
      setLineup(nextLineup);
      setRotationIndex(nextLineup.rotationIndex);
      setHasRotatedInCurrentRun(false); 

      // Persist
      await updateLineup(nextLineup);

      showToast('info', 'Rotated', 'Manual rotation completed.');
  };

  const handleSubSelectBench = (playerId: string) => {
      setIsSubMode(true);
      setSelectedBenchPlayerId(playerId);
      showToast('info', 'Substitution', 'Select a player on court to swap.');
  };

  const handleSubExecute = async (courtPlayerId: string) => {
      if (!isSubMode || !selectedBenchPlayerId || !lineup) return;

      const newOnCourt = lineup.onCourt.map(slot => {
          if (slot.playerId === courtPlayerId) return { ...slot, playerId: selectedBenchPlayerId };
          return slot;
      });
      const newBench = lineup.benchPlayerIds.filter(id => id !== selectedBenchPlayerId);
      newBench.push(courtPlayerId);

      const updatedLineup = { ...lineup, onCourt: newOnCourt, benchPlayerIds: newBench };

      setLineup(updatedLineup);
      setIsSubMode(false);
      setSelectedBenchPlayerId(null);

      // Persist
      await updateLineup(updatedLineup);

      showToast('success', 'Substitution', 'Player swapped successfully.');
  };

  const handleRecordEvent = async () => {
    if (!selectedPlayerId || !selectedFundamental || !selectedOutcome || !match) return;

    setSaving(true);

    const fundamentalConfig = FUNDAMENTAL_CONFIG[selectedFundamental];
    const outcomeConfig = fundamentalConfig.outcomes.find(o => o.code === selectedOutcome);

    // Optimistic Score Update
    if (outcomeConfig) {
        const impact = outcomeConfig.rotationImpact;
        if (impact === 'point_for_us') setTeamPoints(prev => prev + 1);
        else if (impact === 'point_for_them' || impact === 'card_red') setOpponentPoints(prev => prev + 1);
    }

    const newEvent: GameEvent = {
        id: Math.random().toString(36).substr(2, 9),
        matchId: match.id,
        playerId: selectedPlayerId,
        setNumber: currentSet,
        scoreTeam: teamPoints, 
        scoreOpponent: opponentPoints, 
        fundamental: selectedFundamental,
        outcome: selectedOutcome,
        isImportantPoint: isImportant,
        isDecisivePoint: isDecisive,
        timestamp: Date.now()
    };

    try {
        await saveEvent(newEvent);

        const updatedEvents = [...events, newEvent];
        setEvents(updatedEvents);

        // RECOMPUTE STATS
        recomputeDerivedData(updatedEvents, currentSet);

        // Automatic Rotation Logic
        if (outcomeConfig && lineup) {
            const impact = outcomeConfig.rotationImpact;
            let updatedLineup = lineup;
            let shouldPersistLineup = false;

            if (impact === 'point_for_us') {
                if (!hasRotatedInCurrentRun) {
                    updatedLineup = rotateLineupLogic(lineup);
                    setLineup(updatedLineup);
                    setRotationIndex(updatedLineup.rotationIndex);
                    setHasRotatedInCurrentRun(true);
                    shouldPersistLineup = true;
                    showToast('info', 'Side-Out', 'Rotation applied automatically.');
                }
            } else if (impact === 'point_for_them') {
                setHasRotatedInCurrentRun(false);
            } else if (impact === 'card_red') {
                updatedLineup = rotateLineupLogic(lineup);
                setLineup(updatedLineup);
                setRotationIndex(updatedLineup.rotationIndex);
                setHasRotatedInCurrentRun(false); 
                shouldPersistLineup = true;
            }

            if (shouldPersistLineup) {
                await updateLineup(updatedLineup);
            }
        }

        showToast('success', 'Event Saved', `${FUNDAMENTAL_CONFIG[selectedFundamental].label} recorded.`);

        setSelectedFundamental(null);
        setSelectedOutcome(null);
        setSelectedPlayerId(null); 
    } catch (e) {
        showToast('error', 'Save Failed', 'Could not save the event.');
    } finally {
        setSaving(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center font-display text-4xl text-teal animate-pulse">LOADING COURT...</div>;
  if (!match || !lineup) return <div className="h-screen flex items-center justify-center font-display text-4xl text-terracotta">SETUP FAILED</div>;

  // -- RENDER HELPERS --

  const getGridArea = (pos: CourtPosition) => {
      switch(pos) {
          case 4: return 'row-start-1 col-start-1';
          case 3: return 'row-start-1 col-start-2';
          case 2: return 'row-start-1 col-start-3';
          case 5: return 'row-start-2 col-start-1';
          case 6: return 'row-start-2 col-start-2';
          case 1: return 'row-start-2 col-start-3';
      }
  };

  const isFormValid = selectedPlayerId && selectedFundamental && selectedOutcome;

  return (
    <div className="h-[calc(100vh-100px)] flex flex-col font-sans overflow-hidden bg-cream-light">

      {/* 1. TOP HEADER (Scoreboard) */}
      <div className="bg-navy-muted text-cream-light p-3 md:p-4 rounded-b-xl shadow-cartoon flex justify-between items-center z-20 shrink-0">
         <div className="flex items-center gap-4 md:gap-8">
            <div className="text-right">
                <div className="font-title text-5xl md:text-7xl text-lime leading-[0.8]">{teamPoints}</div>
            </div>
            <div className="h-10 w-[3px] bg-white/20"></div>
            <div>
                <div className="font-title text-5xl md:text-7xl text-coral-volley leading-[0.8]">{opponentPoints}</div>
            </div>
         </div>

         <div className="flex flex-col items-center">
             <h1 className="font-title text-2xl md:text-4xl uppercase tracking-wider text-white">{match.opponentName}</h1>
             <div className="flex gap-2 text-xs font-bold uppercase opacity-70 tracking-widest">
                 <span>Set {currentSet}</span> • <span>Rot. {rotationIndex}</span>
             </div>
         </div>

         <div className="flex gap-2">
            <Button variant="danger" size="sm" onClick={onFinished}>
                Finish
            </Button>
         </div>
      </div>

      {/* 2. MAIN LAYOUT */}
      <div className="flex flex-1 min-h-0 gap-4 md:gap-6 p-4 md:p-6">

         {/* LEFT COLUMN: COURT & BENCH */}
         <div className="w-full md:w-[45%] lg:w-[40%] flex flex-col gap-4 min-h-0">

             {/* THE COURT */}
             <div className="relative bg-orange-100 border-4 border-terracotta rounded-xl shadow-cartoon flex-1 min-h-[350px]">
                 {/* Net Marker */}
                 <div className="absolute top-0 left-0 right-0 h-2 bg-white/50 z-0"></div>
                 <div className="absolute top-0 left-1/3 bottom-0 w-1 bg-terracotta/20 z-0"></div>
                 <div className="absolute top-0 right-1/3 bottom-0 w-1 bg-terracotta/20 z-0"></div>
                 <div className="absolute top-1/2 left-0 right-0 h-1 bg-terracotta/20 z-0"></div>

                 {/* Player Grid */}
                 <div className="absolute inset-0 grid grid-cols-3 grid-rows-2 p-2 gap-2 z-10">
                     {lineup.onCourt.map((slot) => {
                         const player = playersById[slot.playerId]?.data;
                         const rating = liveRatings[slot.playerId]?.rating || 6.0;
                         const isSelected = selectedPlayerId === slot.playerId;
                         const roleInitial = player ? getRoleInitial(player.position) : '?';

                         if (!player) return null;

                         return (
                             <div 
                                key={slot.playerId}
                                className={`
                                    relative ${getGridArea(slot.position)}
                                    bg-white border-[3px] border-black rounded-xl p-2
                                    flex flex-col items-center justify-center cursor-pointer transition-all duration-200
                                    ${isSelected ? 'bg-volley-blue text-white ring-4 ring-black/20 shadow-none scale-95' : 'shadow-cartoon hover:-translate-y-1 hover:shadow-cartoon-hover'}
                                    ${isSubMode ? 'animate-pulse ring-4 ring-terracotta' : ''}
                                `}
                                onClick={() => {
                                    if(isSubMode) {
                                        handleSubExecute(slot.playerId);
                                    } else {
                                        setSelectedPlayerId(slot.playerId);
                                        setSelectedPlayerForStats(player); // Also show stats
                                    }
                                }}
                             >
                                 {/* ROLE BADGE */}
                                 <div className="absolute top-1 left-1 bg-black text-cream text-[10px] font-soft px-2 py-[1px] rounded-full uppercase border border-white/20">
                                    {roleInitial}
                                 </div>

                                 <div className="absolute top-1 right-2 text-xs font-bold opacity-30">P{slot.position}</div>

                                 <div className="font-title text-4xl leading-none mt-3">{player.shirtNumber}</div>
                                 <div className="text-xs font-bold uppercase truncate max-w-full">{player.lastName}</div>

                                 {/* RATING LIVE */}
                                 <div className={`
                                     mt-1 px-2 py-[2px] rounded border border-black font-title text-sm
                                     ${rating >= 7.5 ? 'bg-lime text-black' : rating < 5.5 ? 'bg-terracotta text-white' : 'bg-cream-dark text-black'}
                                 `}>
                                     {rating.toFixed(1)}
                                 </div>
                             </div>
                         );
                     })}
                 </div>
             </div>

             {/* ACTIONS BAR (Rotate / Bench) */}
             <div className="flex gap-4 h-32 shrink-0">
                 <button 
                    onClick={handleManualRotate}
                    className="w-24 bg-navy-muted text-cream-light border-[3px] border-black rounded-xl flex flex-col items-center justify-center shadow-cartoon active:shadow-none active:translate-y-1 transition-all"
                 >
                     <span className="text-3xl">↻</span>
                     <span className="font-title text-lg uppercase tracking-wider">Rotate</span>
                 </button>

                 <div className="flex-1 bg-cream-dark border-[3px] border-black rounded-xl p-3 shadow-cartoon overflow-x-auto flex gap-3 items-center">
                     <div className="font-title text-xl text-black/30 vertical-rl rotate-180 text-center">BENCH</div>
                     {lineup.benchPlayerIds.map(pid => {
                         const p = playersById[pid]?.data;
                         if(!p) return null;
                         const isSelectedBench = selectedBenchPlayerId === pid;

                         return (
                            <button
                                key={pid}
                                onClick={() => handleSubSelectBench(pid)}
                                className={`
                                    shrink-0 w-16 h-full bg-white border-2 border-black rounded-lg flex flex-col items-center justify-center transition-all
                                    ${isSelectedBench ? 'bg-terracotta text-white' : 'hover:bg-gray-100'}
                                `}
                            >
                                <span className="font-title text-2xl">{p.shirtNumber}</span>
                                <span className="text-[10px] uppercase font-bold truncate w-full px-1">{p.lastName}</span>
                            </button>
                         );
                     })}
                 </div>
             </div>
         </div>

         {/* RIGHT COLUMN: CONTROLS & STATS */}
         <div className="flex-1 flex flex-col min-h-0 gap-4 overflow-y-auto pr-2">

             {/* 1. INPUT PANEL (Always visible or primary) */}
             <div className="bg-white border-[3px] border-black rounded-xl p-4 shadow-cartoon shrink-0">
                 {/* Header */}
                 <div className="h-12 flex items-center justify-between border-b-2 border-gray-100 pb-2 mb-2">
                     <span className="font-title text-2xl text-navy-muted uppercase">Event Recorder</span>
                     {selectedPlayerId ? (
                         <div className="flex items-center gap-2 bg-volley-blue text-white px-4 py-1 rounded-full border-2 border-black font-bold uppercase text-sm animate-in fade-in slide-in-from-right">
                             <span>#{playersById[selectedPlayerId]?.data.shirtNumber} {playersById[selectedPlayerId]?.data.lastName}</span>
                         </div>
                     ) : (
                        <span className="text-gray-400 font-bold uppercase text-sm animate-pulse">Select a player on court</span>
                     )}
                 </div>

                 {/* Fundamentals */}
                 <div className="grid grid-cols-3 gap-3 mb-3">
                     {(Object.keys(FUNDAMENTAL_CONFIG) as Fundamental[]).map(fund => (
                         <button
                            key={fund}
                            disabled={!selectedPlayerId}
