export const saveMatchEvents = async (matchId: string, events: GameEvent[]) => {
  if (events.length > 0) {
      eventsStore = [...eventsStore, ...events];
  }

  const matchEvents = eventsStore.filter(e => e.matchId === matchId);
  console.log(`Calculating stats for ${matchEvents.length} events in match ${matchId}`);

  const aggStatsByPlayer = aggregatePlayerStats(matchEvents, matchId);

  const playerEvents: Record<string, GameEvent[]> = {};
  matchEvents.forEach(e => {
    if (!playerEvents[e.playerId]) playerEvents[e.playerId] = [];
    playerEvents[e.playerId].push(e);
  });

  const stats: PlayerMatchStats[] = [];

  for (const playerId of Object.keys(playerEvents)) {
    const pEvents = playerEvents[playerId];
    const player = MOCK_PLAYERS.find(p => p.id === playerId);

    if (player) {
      const result = computeVolleyRating(pEvents, { role: player.position });
      const liveStats = aggStatsByPlayer[playerId];

      const totalPoints = liveStats ? (liveStats.attackPoints + liveStats.aces + liveStats.blockPoints) : 0;

      const errors = pEvents.filter(e => e.outcome.includes('error') || e.outcome.includes('fault') || e.outcome.includes('conceded')).length;

      statsStore = statsStore.filter(s => !(s.matchId === matchId && s.playerId === playerId));

      const newStat: PlayerMatchStats = {
        id: `stats_${Date.now()}_${playerId}`,
        matchId,
        playerId,
        rating: result.rating,
        breakdown: result.breakdown,
        totalPoints,
        errors
      };

      stats.push(newStat);
    }
  }

  statsStore = [...statsStore, ...stats];
  return stats;
};

