/**
 * Restituisce tutte le partite in cui il player ha almeno un evento registrato.
 */
export async function getPlayerMatches(playerId: string): Promise<Match[]> {
  const matchIds = new Set<string>();
  events.forEach((ev) => {
    if (ev.playerId === playerId) {
      matchIds.add(ev.matchId);
    }
  });
  return matches.filter((m) => matchIds.has(m.id));
}

/**
 * Restituisce le stats per ogni partita in cui il player ha giocato,
 * usando computeVolleyRating e la logica già in uso per PlayerMatchStats.
 */
export async function getPlayerMatchStatsForPlayer(playerId: string): Promise<PlayerMatchStats[]> {
  const result: PlayerMatchStats[] = [];

  const player = players.find((p) => p.id === playerId);
  if (!player) return result;

  const playerMatches = await getPlayerMatches(playerId);

  for (const match of playerMatches) {
    const evForMatch = events.filter((ev) => ev.matchId === match.id && ev.playerId === playerId);
    const ratingResult = computeVolleyRating(evForMatch, { position: player.position });

    // Totals semplici (puoi riusare la logica di aggregatePlayerStats se vuoi)
    let attacks = 0;
    let attackPoints = 0;
    let attackErrors = 0;
    let serves = 0;
    let aces = 0;
    let serveErrors = 0;
    let receptions = 0;
    let perfectReceptions = 0;
    let negativeReceptions = 0;
    let blocks = 0;
    let blockPoints = 0;
    let digs = 0;

    for (const ev of evForMatch) {
      switch (ev.fundamental) {
        case 'attack':
          attacks++;
          if (ev.outcomeCode === 'attack_point') attackPoints++;
          if (ev.outcomeCode === 'attack_error' || ev.outcomeCode === 'attack_blocked') attackErrors++;
          break;
        case 'serve':
          serves++;
          if (ev.outcomeCode === 'serve_ace') aces++;
          if (ev.outcomeCode === 'serve_error') serveErrors++;
          break;
        case 'reception':
          receptions++;
          if (ev.outcomeCode === 'reception_perfect') perfectReceptions++;
          if (ev.outcomeCode === 'reception_negative' || ev.outcomeCode === 'reception_ace_conceded') negativeReceptions++;
          break;
        case 'block':
          blocks++;
          if (ev.outcomeCode === 'block_point') blockPoints++;
          break;
        case 'defense':
          if (ev.outcomeCode === 'defense_great' || ev.outcomeCode === 'defense_ok') digs++;
          break;
      }
    }

    result.push({
      matchId: match.id,
      playerId,
      teamId: player.teamId,
      rating: ratingResult.rating,
      breakdown: ratingResult.breakdown,
      totals: {
        attacks,
        attackPoints,
        attackErrors,
        serves,
        aces,
        serveErrors,
        receptions,
        perfectReceptions,
        negativeReceptions,
        blocks,
        blockPoints,
        digs,
      },
    });
  }

  return result;
}
