export const getPlayerMatches = async (playerId: string): Promise<Match[]> => {
    const events = load<GameEvent[]>(KEY_EVENTS, []);
    const matches = load<Match[]>(KEY_MATCHES, []);

    // Check real events first
    const matchIds = new Set<string>();
    events.forEach((ev) => {
        if (ev.playerId === playerId) {
            matchIds.add(ev.matchId);
        }
    });

    // For demo continuity with Seed Data, if a seed match is completed but has no events in LS yet,
    // we still return it so the profile doesn't look empty for the seed players.
    // In a real app, strictly filter by matchIds.
    if (events.length === 0) {
         // Fallback for seed players to show seed matches
         return matches.filter(m => m.status === 'completed');
    }

    return matches.filter(m => matchIds.has(m.id));
};

