export const getPlayerMatchStatsForPlayer = async (playerId: string): Promise<PlayerMatchStats[]> => {
  return new Promise(async (resolve) => {
      const result: PlayerMatchStats[] = [];
      const players = load<Player[]>(KEY_PLAYERS, []);
      const player = players.find((p) => p.id === playerId);

      if (!player) { resolve([]); return; }

      const allMatches = load<Match[]>(KEY_MATCHES, []);
      const allEvents = load<GameEvent[]>(KEY_EVENTS, []);

      for (const match of allMatches) {
        let evForMatch = allEvents.filter((ev) => ev.matchId === match.id && ev.playerId === playerId);

        // --- DEMO FAKE DATA GENERATOR IF EMPTY & SEED MATCH ---
        // Keeps the app looking good before user enters data
        if (evForMatch.length === 0 && (match.id === 'm1' || match.id === 'm2') && playerId.startsWith('p')) {
             const isM1 = match.id === 'm1';
             result.push({
                 id: `fake_${match.id}`,
                 matchId: match.id,
                 playerId: playerId,
                 teamId: player.teamId,
                 matchDate: match.date,
                 opponentName: match.opponentName,
                 rating: isM1 ? 8.2 : 6.5,
                 breakdown: { attack: 0, serve: 0, reception: 0, block: 0, defense: 0 },
                 totalPoints: isM1 ? 15 : 8,
                 errors: isM1 ? 2 : 5,
                 totals: {
                     attacks: isM1 ? 20 : 15,
                     attackPoints: isM1 ? 10 : 5,
                     attackErrors: isM1 ? 2 : 4,
                     serves: 12,
                     aces: isM1 ? 3 : 1,
                     serveErrors: 2,
                     receptions: 25,
                     perfectReceptions: isM1 ? 15 : 8,
                     negativeReceptions: 2,
                     blocks: 5,
                     blockPoints: isM1 ? 2 : 1,
                     digs: 8
                 }
             });
             continue;
        }
        // -----------------------------------------

        if (evForMatch.length === 0) continue;

        const ratingResult = computeVolleyRating(evForMatch, { role: player.position });

        let attacks = 0;
        let attackPoints = 0;
        let attackErrors = 0;
        let serves = 0;
        let aces = 0;
        let serveErrors = 0;
        let receptions = 0;
        let perfectReceptions = 0;
        let negativeReceptions = 0;
        let blocks = 0;
        let blockPoints = 0;
        let digs = 0;

        for (const ev of evForMatch) {
          switch (ev.fundamental) {
            case Fundamental.ATTACK:
              attacks++;
              if (ev.outcome === 'attack_point') attackPoints++;
              if (ev.outcome === 'attack_error' || ev.outcome === 'attack_blocked') attackErrors++;
              break;
            case Fundamental.SERVE:
              serves++;
              if (ev.outcome === 'serve_ace') aces++;
              if (ev.outcome === 'serve_error') serveErrors++;
              break;
            case Fundamental.RECEPTION:
              receptions++;
              if (ev.outcome === 'reception_perfect') perfectReceptions++;
              if (ev.outcome === 'reception_negative' || ev.outcome === 'reception_ace_conceded') negativeReceptions++;
              break;
            case Fundamental.BLOCK:
              blocks++;
              if (ev.outcome === 'block_point') blockPoints++;
              break;
            case Fundamental.DEFENSE:
              if (ev.outcome === 'defense_great' || ev.outcome === 'defense_ok') digs++;
              break;
          }
        }

        result.push({
          id: `s_${match.id}_${playerId}`,
          matchId: match.id,
          playerId,
          teamId: player.teamId,
          matchDate: match.date,
          opponentName: match.opponentName,
          rating: ratingResult.rating,
          breakdown: ratingResult.breakdown,
          totalPoints: attackPoints + aces + blockPoints,
          errors: attackErrors + serveErrors, 
          totals: {
            attacks,
            attackPoints,
            attackErrors,
            serves,
            aces,
            serveErrors,
            receptions,
            perfectReceptions,
            negativeReceptions,
            blocks,
            blockPoints,
            digs,
          },
        });
      }

      setTimeout(() => resolve(result), 300);
  });
};

