    const [teamPlayers, setTeamPlayers] = useState<Player[]>([]);
    const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isAddingNew, setIsAddingNew] = useState(false);

    useEffect(() => {
      getTeamPlayers('t1').then(setTeamPlayers);
    }, []);

    const handleEditChange = (field: keyof Player, value: string) => {
      if (!editingPlayer) return;
      let updated: Player = { ...editingPlayer };

      if (field === 'shirtNumber') {
        updated.shirtNumber = parseInt(value || '0', 10);
      } else if (field === 'position') {
        updated.position = value as PlayerPosition;
      } else {
        (updated as any)[field] = value;
      }

      setEditingPlayer(updated);
    };

    const handleCreateNewClick = () => {
        const newP: Player = {
            id: '', // temp
            teamId: 't1',
            firstName: '',
            lastName: '',
            position: PlayerPosition.OUTSIDE_HITTER,
            shirtNumber: 0,
            averageRating: 6.0,
            matchesPlayed: 0,
            region: 'Lombardia',
            category: 'U19'
        };
        setEditingPlayer(newP);
        setIsAddingNew(true);
    };

    const handleSavePlayer = async () => {
      if (!editingPlayer) return;
      setIsSaving(true);
      try {
        if (isAddingNew) {
            const created = await createPlayer(editingPlayer);
            setTeamPlayers(prev => [...prev, created]);
            addToast('success', 'Player Added', `${created.firstName} joined the team.`);
        } else {
            const saved = await updatePlayer(editingPlayer);
            setTeamPlayers((prev) =>
            prev.map((p) => (p.id === saved.id ? saved : p))
            );
            addToast('success', 'Player Updated', `${saved.firstName} updated.`);
        }
        setEditingPlayer(null);
        setIsAddingNew(false);
      } catch (e) {
        addToast('error', 'Error', 'Failed to save player');
      } finally {
        setIsSaving(false);
      }
    };

    return (
      <div className="flex flex-col md:flex-row gap-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
        <div className="flex-1">
          <div className="flex justify-between items-center mb-6">
             <h1 className="font-title text-5xl uppercase">
                Team Roster
             </h1>
             <Button onClick={handleCreateNewClick}>+ Add Player</Button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {teamPlayers.map((p) => (
              <div
                key={p.id}
                className="bg-cream-dark p-4 border-2 border-black rounded-card shadow-cartoon flex flex-col gap-3 hover:bg-white transition-colors"
              >
