                  <div>
                    <div className="font-title text-2xl leading-none">
                      {p.firstName} {p.lastName}
                    </div>
                    <div className="text-xs uppercase text-terracotta font-soft font-bold">
                      {p.position.replace('_', ' ')}
                    </div>
                  </div>
                </div>

                {typeof p.averageRating === 'number' && (
                  <div className="flex items-center justify-between text-xs font-soft">
                    <span className="text-black/70">Rating medio</span>
                    <span className="bg-lime border-2 border-black rounded-lg px-2 py-[2px] font-title text-lg">
                      {p.averageRating.toFixed(1)}
                    </span>
                  </div>
                )}

