                  <Button
                    size="sm"
                    variant="secondary"
                    className="flex-1"
                    onClick={() => {
                      setSelectedPlayer(p);
                      navigate(`/players/${p.id}`);
                    }}
                  >
                    Scheda
                  </Button>
                  <Button
                    size="sm"
                    className="flex-1"
                    onClick={() => { setIsAddingNew(false); setEditingPlayer(p); }}
                  >
                    Modifica
                  </Button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Pannello di editing giocatore */}
        {editingPlayer && (
          <aside className="md:w-80 bg-cream-dark border-2 border-black rounded-card shadow-cartoon p-4 h-fit sticky top-20 animate-in slide-in-from-right fade-in duration-300">
            <div className="flex items-center justify-between mb-3">
              <div>
                <div className="text-xs font-soft uppercase text-terracotta font-bold">
                  {isAddingNew ? 'Nuovo Giocatore' : 'Modifica Giocatore'}
                </div>
                <div className="font-title text-2xl">
                  {isAddingNew ? 'New' : `#${editingPlayer.shirtNumber}`}
                </div>
              </div>
              <button
                type="button"
                className="text-xs font-soft underline"
                onClick={() => setEditingPlayer(null)}
