              <div>
                <label className="block text-xs uppercase mb-1 font-bold">Cognome</label>
                <input
                  className="w-full border-2 border-black rounded-card px-2 py-1 bg-white"
                  value={editingPlayer.lastName}
                  onChange={(e) => handleEditChange('lastName', e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs uppercase mb-1 font-bold">Numero maglia</label>
                <input
                  type="number"
                  className="w-full border-2 border-black rounded-card px-2 py-1 bg-white"
                  value={editingPlayer.shirtNumber}
                  onChange={(e) => handleEditChange('shirtNumber', e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs uppercase mb-1 font-bold">Ruolo</label>
                <select
                  className="w-full border-2 border-black rounded-card px-2 py-1 bg-white"
                  value={editingPlayer.position}
                  onChange={(e) => handleEditChange('position', e.target.value)}
                >
                  <option value="setter">Setter</option>
                  <option value="opposite">Opposto</option>
                  <option value="outside_hitter">Schiacciatore</option>
                  <option value="middle_blocker">Centrale</option>
                  <option value="libero">Libero</option>
                </select>
              </div>
            </div>

            <Button
              size="sm"
              className="mt-4 w-full"
              onClick={handleSavePlayer}
              disabled={isSaving}
            >
              {isSaving ? 'Salvataggio...' : (isAddingNew ? 'Crea Giocatore' : 'Salva modifiche')}
            </Button>
          </aside>
        )}
      </div>
    );
  };

  // Route Matcher
  let Content = <LandingPage />;

  if (user) {
    if (route === '/dashboard' || route === '/') {
      Content = <Dashboard user={user} onNavigate={navigate} />;
    } else if (route.startsWith('/scout/')) {
      const matchId = route.split('/')[2];
      Content = (
        <Scouting
          matchId={matchId}
          user={user}
          onFinished={() => navigate('/dashboard')}
          showToast={addToast}
        />
      );
    } else if (route === '/teams') {
      Content = <TeamsView />;
    } else if (route.startsWith('/players/')) {
      const pId = route.split('/')[2];
      if (selectedPlayer && selectedPlayer.id === pId) {
        Content = <PlayerProfile player={selectedPlayer} />;
      } else {
        Content = <PlayerLoader playerId={pId} />;
      }
    } else if (route === '/leaderboards') {
      Content = <Leaderboard />;
    }
  } else if (route === '/login') {
    Content = <LandingPage />;
  }

  return (
    <Layout
      user={user || undefined}
      onLogout={() => {
        setUser(null);
        navigate('/');
        addToast('info', 'Logged Out', 'See you next time!');
      }}
      onNavigate={navigate}
      currentPath={route}
    >
      {Content}
      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </Layout>
  );
};

