      { code: 'net_fault',      label: 'Invasione',      symbol: '=',  rotationImpact: 'point_for_them' },
      { code: 'rotation_fault', label: 'Fallo Form.', symbol: '=', rotationImpact: 'point_for_them' },
      { code: 'card_red',       label: 'Rosso (Pt avv)',  symbol: 'R',  rotationImpact: 'card_red' },
    ],
  },
};

// --- VOLLEYBALL RULES HELPERS ---

// Is this action valid for this player?
const isActionAllowed = (player: Player, fundamental: Fundamental, courtPos: CourtPosition): boolean => {
    if (player.position === PlayerPosition.LIBERO) {
        if (fundamental === Fundamental.SERVE) return false; // Most leagues
        if (fundamental === Fundamental.BLOCK) return false;
        if (fundamental === Fundamental.ATTACK && [2,3,4].includes(courtPos)) return false; // Libero front row attack illegal
    }
    return true;
};

const getRoleInitial = (position: PlayerPosition): string => {
  switch (position) {
    case PlayerPosition.SETTER: return 'P';
    case PlayerPosition.OPPOSITE: return 'O';
    case PlayerPosition.OUTSIDE_HITTER: return 'S';
    case PlayerPosition.MIDDLE_BLOCKER: return 'C';
    case PlayerPosition.LIBERO: return 'L';
    default: return '?';
  }
};

const getOutcomeColor = (code: OutcomeCode) => {
    if (code.includes('point') || code.includes('ace') || code.includes('perfect') || code.includes('great')) return 'bg-lime text-black border-black';
    if (code.includes('error') || code.includes('fault') || code.includes('conceded') || code.includes('blocked') || code.includes('slash')) return 'bg-terracotta text-cream border-black';
    return 'bg-cream-dark text-black border-black';
};

const rotateLineupLogic = (currentLineup: MatchLineup): MatchLineup => {
    const nextPosMap: Record<number, CourtPosition> = {
        1: 6, 6: 5, 5: 4, 4: 3, 3: 2, 2: 1
    };
    const nextOnCourt = currentLineup.onCourt.map(slot => ({
        ...slot,
        position: nextPosMap[slot.position]
    }));
    return {
        ...currentLineup,
        onCourt: nextOnCourt,
        rotationIndex: currentLineup.rotationIndex + 1
    };
};

const isSetOver = (set: number, us: number, them: number): { finished: boolean; winner: 'us' | 'them' | null } => {
  const target = set === 5 ? 15 : 25;
  if (us >= target || them >= target) {
    const diff = Math.abs(us - them);
    if (diff >= 2) {
      if (us > them) return { finished: true, winner: 'us' };
      return { finished: true, winner: 'them' };
    }
  }
  return { finished: false, winner: null };
};

// --- COMPONENT ---

export const Scouting: React.FC<ScoutingProps> = ({ matchId, user, onFinished, showToast }) => {
  // Data
  const [match, setMatch] = useState<Match | null>(null);
  const [players, setPlayers] = useState<Player[]>([]);
  const [lineup, setLineup] = useState<MatchLineup | null>(null);
  const [lastEvent, setLastEvent] = useState<GameEvent | null>(null);

  // Game State
  const [currentSet, setCurrentSet] = useState(1);
  const [teamPoints, setTeamPoints] = useState(0);
  const [opponentPoints, setOpponentPoints] = useState(0);
  const [hasRotatedInCurrentRun, setHasRotatedInCurrentRun] = useState<boolean>(false);
  const [rotationIndex, setRotationIndex] = useState(0);

  // Interaction
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFundamental, setSelectedFundamental] = useState<Fundamental | null>(null);
  const [selectedOutcome, setSelectedOutcome] = useState<OutcomeCode | null>(null);
  const [isSubMode, setIsSubMode] = useState(false);
  const [selectedBenchPlayerId, setSelectedBenchPlayerId] = useState<string | null>(null);

  const playersById = useMemo(() => {
      const map: Record<string, { position: PlayerPosition, data: Player }> = {};
      players.forEach(p => map[p.id] = { position: p.position, data: p });
      return map;
  }, [players]);

  const liveRatings = useMemo(() => {
      // In a real app we'd fetch all events again to recalc, here we rely on basic continuity or re-fetch
      // For MVP visual we just default or would need a robust event store in context
      return {}; 
  }, []);

  // --- INIT ---
  useEffect(() => {
    const init = async () => {
       try {
           const [matches, teamPlayers, initialLineup] = await Promise.all([
               getMatches('t1'),
               getTeamPlayers('t1'),
               getInitialLineupForMatch(matchId)
           ]);
           const m = matches.find(x => x.id === matchId);
           setMatch(m || null);
           setPlayers(teamPlayers);
           setLineup(initialLineup);
       } catch (error) {
           showToast('error', 'Errore', 'Impossibile caricare i dati del match.');
       } finally {
           setLoading(false);
       }
    };
    init();
  }, [matchId]);

  // --- SET LOGIC ---
  useEffect(() => {
    const { finished, winner } = isSetOver(currentSet, teamPoints, opponentPoints);
    if (finished) {
        showToast('success', `SET ${currentSet} FINITO!`, `Vincitore: ${winner === 'us' ? 'NOI' : 'LORO'}`);
        if (currentSet < 5) {
            setTimeout(() => {
                const nextSet = currentSet + 1;
                setCurrentSet(nextSet);
                setTeamPoints(0);
                setOpponentPoints(0);
                setHasRotatedInCurrentRun(false);
                // Reset rotation to 0 usually in new set or keep lineup? Assuming lineup stays but pos resets?
                // For MVP we keep lineup current position but points reset.
            }, 3000);
        } else {
            onFinished();
        }
    }
  }, [teamPoints, opponentPoints]);

  // --- ACTIONS ---

  const handleUndo = async () => {
      if (!lastEvent) return;

      // Revert Score
      const outcome = lastEvent.outcome;
      if (['attack_point','serve_ace','block_point','attack_tool'].includes(outcome)) {
          setTeamPoints(p => Math.max(0, p - 1));
      } else if (['serve_error','attack_error','reception_ace_conceded','block_invasion','net_fault','reception_slash'].includes(outcome)) {
          setOpponentPoints(p => Math.max(0, p - 1));
      }

      await deleteLastEvent(matchId);
      setLastEvent(null);
      showToast('info', 'Annullato', 'Ultimo evento rimosso');
  };

  const handleRecordEvent = async () => {
    if (!selectedPlayerId || !selectedFundamental || !selectedOutcome || !match || !lineup) return;
    setSaving(true);

    const newEvent: GameEvent = {
        id: Math.random().toString(36).substr(2, 9),
        matchId: match.id,
        playerId: selectedPlayerId,
        setNumber: currentSet,
        scoreTeam: teamPoints,
        scoreOpponent: opponentPoints,
        fundamental: selectedFundamental,
        outcome: selectedOutcome,
        isImportantPoint: teamPoints > 20 || opponentPoints > 20,
        isDecisivePoint: Math.abs(teamPoints - opponentPoints) <= 2 && (teamPoints > 23 || opponentPoints > 23),
        timestamp: Date.now(),
        lineupRotation: lineup.rotationIndex
    };

    try {
        await saveEvent(newEvent);
        setLastEvent(newEvent);

        // Score Updates & Notifications
        const outcomeConfig = FUNDAMENTAL_CONFIG[selectedFundamental].outcomes.find(o => o.code === selectedOutcome);

        if (outcomeConfig?.rotationImpact === 'point_for_us') {
            setTeamPoints(prev => prev + 1);
            if (selectedOutcome === 'serve_ace') showToast('success', 'ACE!', 'Battuta vincente!');
            if (selectedOutcome === 'block_point') showToast('success', 'MONSTER BLOCK!', 'Muro punto!');
            if (selectedOutcome === 'attack_point') showToast('success', 'KILL!', 'Attacco vincente!');

            // Rotation Logic (Side-out)
            if (!hasRotatedInCurrentRun) {
                const nextLineup = rotateLineupLogic(lineup);
                setLineup(nextLineup);
                setRotationIndex(nextLineup.rotationIndex);
                setHasRotatedInCurrentRun(true);
            }
        } else if (outcomeConfig?.rotationImpact === 'point_for_them') {
            setOpponentPoints(prev => prev + 1);
            setHasRotatedInCurrentRun(false); // Reset for next time we win point
        }

        setSelectedFundamental(null);
        setSelectedOutcome(null);
        setSelectedPlayerId(null);
    } catch (e) {
        showToast('error', 'Errore Salvataggio');
    } finally {
        setSaving(false);
    }
  };

  const handleManualRotate = () => {
      if(!lineup) return;
      const next = rotateLineupLogic(lineup);
      setLineup(next);
      setRotationIndex(next.rotationIndex);
      setHasRotatedInCurrentRun(false);
  };

  const handleSubExecute = (courtPlayerId: string) => {
      if (!isSubMode || !selectedBenchPlayerId || !lineup) return;
      const newOnCourt = lineup.onCourt.map(slot => slot.playerId === courtPlayerId ? { ...slot, playerId: selectedBenchPlayerId } : slot);
      const newBench = lineup.benchPlayerIds.filter(id => id !== selectedBenchPlayerId);
      newBench.push(courtPlayerId);
      setLineup({ ...lineup, onCourt: newOnCourt, benchPlayerIds: newBench });
      setIsSubMode(false);
      setSelectedBenchPlayerId(null);
      showToast('success', 'Cambio Effettuato');
  };

  // --- RENDER ---
  if (loading) return <div className="h-screen flex items-center justify-center font-display text-4xl animate-pulse">CARICAMENTO CAMPO...</div>;
  if (!match || !lineup) return <div>Errore setup match</div>;

  const getGridArea = (pos: CourtPosition) => {
      switch(pos) {
          case 4: return 'row-start-1 col-start-1';
          case 3: return 'row-start-1 col-start-2';
          case 2: return 'row-start-1 col-start-3';
          case 5: return 'row-start-2 col-start-1';
          case 6: return 'row-start-2 col-start-2';
          case 1: return 'row-start-2 col-start-3';
      }
  };

  return (
    <div className="h-[calc(100vh-80px)] flex flex-col font-sans overflow-hidden bg-cream-light">

      {/* SCOREBOARD HEADER */}
      <div className="bg-navy text-cream p-4 flex justify-between items-center shadow-lg z-10">
         <div className="flex items-center gap-6">
            <div className="text-right">
                <div className="font-title text-6xl text-lime leading-[0.8]">{teamPoints}</div>
                <div className="text-xs uppercase opacity-70">Noi</div>
            </div>
            <div className="h-12 w-[2px] bg-white/20"></div>
            <div>
                <div className="font-title text-6xl text-terracotta leading-[0.8]">{opponentPoints}</div>
                <div className="text-xs uppercase opacity-70">Loro</div>
            </div>
         </div>
         <div className="flex flex-col items-center">
             <div className="font-bold text-xl uppercase tracking-widest">{match.opponentName}</div>
             <div className="flex gap-4 text-xs font-mono bg-black/20 px-3 py-1 rounded-full mt-1">
                 <span>SET: {currentSet}</span>
                 <span>ROT: P{lineup.onCourt.find(s => s.position === 1)?.playerId ? '1' : '?'}</span>
             </div>
         </div>
         <div className="flex gap-2">
             {lastEvent && (
                 <Button variant="secondary" size="sm" onClick={handleUndo}>↩ UNDO</Button>
             )}
             <Button variant="danger" size="sm" onClick={onFinished}>FINISCI</Button>
         </div>
      </div>

      <div className="flex flex-1 min-h-0 gap-4 p-4">

         {/* LEFT: COURT */}
         <div className="w-full md:w-[45%] flex flex-col gap-4">
             <div className="relative bg-orange-100 border-4 border-terracotta rounded-lg shadow-inner flex-1 min-h-[400px]">
                 {/* 3-meter line */}
                 <div className="absolute top-1/2 left-0 right-0 h-1 bg-terracotta/40 z-0"></div>
                 <div className="absolute top-1/2 right-2 text-terracotta/40 font-bold text-xs">Linea 3m</div>

                 <div className="absolute inset-0 grid grid-cols-3 grid-rows-2 p-2 gap-2 z-10">
                     {lineup.onCourt.map((slot) => {
                         const player = playersById[slot.playerId]?.data;
                         if (!player) return null;
                         const isSelected = selectedPlayerId === slot.playerId;
                         const isLibero = player.position === PlayerPosition.LIBERO;
                         const isBackRow = [1,6,5].includes(slot.position);

                         return (
                             <div 
                                key={slot.playerId}
                                className={`
                                    relative ${getGridArea(slot.position)}
                                    bg-white border-[3px] rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all
                                    ${isSelected ? 'border-teal bg-teal/10 scale-95 ring-4 ring-teal/30' : 'border-black hover:bg-gray-50'}
                                    ${isSubMode ? 'animate-pulse ring-4 ring-terracotta' : ''}
                                `}
                                onClick={() => isSubMode ? handleSubExecute(slot.playerId) : setSelectedPlayerId(slot.playerId)}
                             >
                                 <div className="absolute top-2 left-2 bg-black text-white text-[10px] px-1 rounded uppercase">
                                    {getRoleInitial(player.position)}
                                 </div>
                                 <div className="absolute top-2 right-2 text-gray-400 font-bold text-xs">P{slot.position}</div>

                                 <div className="font-display text-5xl">{player.shirtNumber}</div>
                                 <div className="text-xs font-bold uppercase truncate w-full text-center px-1">{player.lastName}</div>

                                 {isLibero && <div className="absolute bottom-1 bg-lime text-black text-[9px] px-1 rounded font-bold">LIBERO</div>}
                             </div>
                         );
                     })}
                 </div>
             </div>

             {/* BENCH & ROTATE */}
             <div className="flex gap-4 h-24">
                 <button onClick={handleManualRotate} className="w-20 bg-navy text-cream rounded-lg border-2 border-black flex flex-col items-center justify-center shadow-cartoon active:translate-y-1 active:shadow-none">
                     <span className="text-2xl">↻</span>
                 </button>
                 <div className="flex-1 bg-white border-2 border-black rounded-lg p-2 flex gap-2 overflow-x-auto items-center">
                     <div className="text-[10px] uppercase font-bold text-gray-400 w-4 break-words text-center">PANCHINA</div>
                     {lineup.benchPlayerIds.map(pid => {
                         const p = playersById[pid]?.data;
                         if(!p) return null;
                         return (
                            <button key={pid} onClick={() => { setIsSubMode(true); setSelectedBenchPlayerId(pid); }} 
                                className={`h-full aspect-square border-2 rounded flex flex-col items-center justify-center ${selectedBenchPlayerId === pid ? 'bg-terracotta text-white border-black' : 'bg-gray-100 border-gray-300'}`}>
                                <span className="font-display text-xl">{p.shirtNumber}</span>
                            </button>
                         );
                     })}
                 </div>
             </div>
         </div>

         {/* RIGHT: CONTROLS */}
         <div className="flex-1 bg-white border-4 border-black rounded-xl p-4 flex flex-col shadow-cartoon">
             <div className="mb-4 flex justify-between items-center border-b-2 border-gray-100 pb-2">
                 <h2 className="font-title text-3xl">SCOUTING</h2>
                 {selectedPlayerId ? (
                     <div className="font-bold text-teal uppercase">{playersById[selectedPlayerId]?.data.firstName} #{playersById[selectedPlayerId]?.data.shirtNumber}</div>
                 ) : <div className="text-gray-400 text-sm uppercase">Seleziona giocatore</div>}
             </div>

             {/* FUNDAMENTALS */}
             <div className="grid grid-cols-3 gap-3 mb-4">
                 {(Object.keys(FUNDAMENTAL_CONFIG) as Fundamental[]).filter(f => f !== 'set').map(fund => {
                     // Disable invalid actions based on rules
                     const player = selectedPlayerId ? playersById[selectedPlayerId]?.data : null;
                     const slot = lineup.onCourt.find(s => s.playerId === selectedPlayerId);
                     const disabled = !player || !isActionAllowed(player, fund, slot?.position as CourtPosition);

                     return (
                        <button
                            key={fund}
                            disabled={disabled}
                            onClick={() => { setSelectedFundamental(fund); setSelectedOutcome(null); }}
                            className={`
                                py-3 font-title text-xl uppercase tracking-wider border-2 border-black rounded-lg transition-all
                                ${selectedFundamental === fund ? 'bg-black text-lime translate-y-[2px]' : 'bg-white hover:bg-lime/20 shadow-cartoon-sm'}
                                ${disabled ? 'opacity-30 cursor-not-allowed bg-gray-100 shadow-none' : ''}
                            `}
                        >
                            {FUNDAMENTAL_CONFIG[fund].label}
                        </button>
                     );
                 })}
             </div>

             {/* OUTCOMES */}
             <div className="flex-1 bg-gray-50 border-2 border-black/10 rounded-xl p-4 overflow-y-auto mb-4">
                {selectedFundamental ? (
                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
                        {FUNDAMENTAL_CONFIG[selectedFundamental].outcomes.map(outcome => (
                            <button
                                key={outcome.code}
                                onClick={() => setSelectedOutcome(outcome.code)}
                                className={`
                                    h-16 rounded-lg border-2 flex flex-col items-center justify-center transition-all
                                    ${selectedOutcome === outcome.code ? 'ring-4 ring-black scale-95' : 'shadow-sm hover:translate-y-[-2px]'}
                                    ${getOutcomeColor(outcome.code)}
                                `}
                            >
                                <span className="font-bold text-sm leading-none mb-1">{outcome.label}</span>
                                <span className="font-mono text-xs opacity-70">{outcome.symbol}</span>
                            </button>
                        ))}
                    </div>
                ) : (
                    <div className="h-full flex items-center justify-center text-gray-400 font-bold uppercase text-sm">
                        Seleziona un fondamentale
                    </div>
                )}
             </div>

             <Button size="xl" onClick={handleRecordEvent} disabled={!selectedOutcome || saving} className="w-full">
                 {saving ? '...' : 'REGISTRA EVENTO'}
             </Button>
         </div>
      </div>
    </div>
  );
};

