  'defense_error': -0.15,
  'defense_cover': 0.05,

  // Other
  'net_fault': -0.20,
  'rotation_fault': -0.20,
  'card_yellow': -0.30,
  'card_red': -0.60,
  'generic_error': -0.20
};

/**
 * Role-specific multipliers.
 * Certain fundamentals weigh more heavily for specific roles.
 * e.g., Setters are penalized less for poor blocks but rewarded more for dumps (attacks).
 */
const ROLE_MULTIPLIERS: Record<PlayerPosition, Partial<Record<Fundamental, number>>> = {
  [PlayerPosition.LIBERO]: {
    [Fundamental.RECEPTION]: 1.2,
    [Fundamental.DEFENSE]: 1.3,
    [Fundamental.ATTACK]: 0, // Should not happen usually
    [Fundamental.SERVE]: 0, // Usually doesn't serve in modern rules (often replaced)
    [Fundamental.BLOCK]: 0
  },
  [PlayerPosition.SETTER]: {
    [Fundamental.SERVE]: 1.1,
    [Fundamental.BLOCK]: 1.1, // Blocking is harder for setters typically
    [Fundamental.DEFENSE]: 1.1,
    [Fundamental.ATTACK]: 1.5 // Setter dumps are valuable
  },
  [PlayerPosition.MIDDLE_BLOCKER]: {
    [Fundamental.BLOCK]: 1.2,
    [Fundamental.ATTACK]: 1.1,
    [Fundamental.DEFENSE]: 0.9, // Less expected to dig
    [Fundamental.RECEPTION]: 0.5 // Rarely receives
  },
  [PlayerPosition.OUTSIDE_HITTER]: {
    [Fundamental.ATTACK]: 1.0,
    [Fundamental.RECEPTION]: 1.1, // Critical for OH
    [Fundamental.SERVE]: 1.0,
    [Fundamental.BLOCK]: 1.0
  },
  [PlayerPosition.OPPOSITE]: {
    [Fundamental.ATTACK]: 1.2, // Main job
    [Fundamental.SERVE]: 1.1,
    [Fundamental.BLOCK]: 1.1,
    [Fundamental.RECEPTION]: 0.5 // Rarely receives
  }
};

/**
 * Computes the rating for a single player in a single match based on a list of events.
 * 
 * Algorithm:
 * 1. Start with BASE_RATING (6.0).
 * 2. Iterate through events involving the player.
 * 3. Apply base score for the outcome.
 * 4. Apply Context Multipliers (Important Point / Decisive Point).
 * 5. Apply Role Multipliers (e.g., Liberos value defense more).
 * 6. Sum the delta and clamp between MIN_RATING (3.5) and MAX_RATING (10.0).
 */
export const computeVolleyRating = (events: GameEvent[], context: RatingContext): RatingResult => {
  let deltaTotal = 0;

  const breakdown = {
    attack: 0,
    serve: 0,
    reception: 0,
    block: 0,
    defense: 0
  };

  events.forEach(event => {
    let score = SCORE_VALUES[event.outcome] || 0;

    // 1. Context Multipliers
    if (event.isDecisivePoint) {
      score *= 1.5;
    } else if (event.isImportantPoint) {
      score *= 1.2;
    }

    // 2. Role Multipliers
    const roleMultipliers = ROLE_MULTIPLIERS[context.role];
    const multiplier = roleMultipliers[event.fundamental] ?? 1.0;
    score *= multiplier;

    // 3. Accumulate
    deltaTotal += score;

    // 4. Breakdown accumulation (unweighted by role, just raw contribution to score)
    switch(event.fundamental) {
      case Fundamental.ATTACK: breakdown.attack += score; break;
      case Fundamental.SERVE: breakdown.serve += score; break;
      case Fundamental.RECEPTION: breakdown.reception += score; break;
      case Fundamental.BLOCK: breakdown.block += score; break;
      case Fundamental.DEFENSE: breakdown.defense += score; break;
    }
  });

  // Clamp rating
  let finalRating = BASE_RATING + deltaTotal;
  finalRating = Math.max(MIN_RATING, Math.min(MAX_RATING, finalRating));

  // Round to 1 decimal
  finalRating = Math.round(finalRating * 10) / 10;

  return {
    rating: finalRating,
    breakdown
  };
};

import React, { useState, useEffect, useMemo } from 'react';
