import { GameEvent, MatchLineup, CourtPosition, RotationImpact, Fundamental, OutcomeCode } from '../types';

export interface MatchState {
  currentSet: number;
  teamPoints: number;
  opponentPoints: number;
  currentLineup: MatchLineup;
  servingSide: 'us' | 'them';
  lastEvent: GameEvent | null;
  hasRotatedInCurrentRun: boolean; // Did we already rotate on this service turn?
}

// Helper to determine impact
const getImpact = (outcome?: OutcomeCode): RotationImpact => {
  if (!outcome) return 'neutral';
  if (['attack_point', 'serve_ace', 'block_point', 'attack_tool'].includes(outcome)) return 'point_for_us';
  if (['serve_error', 'attack_error', 'reception_ace_conceded', 'block_invasion', 'net_fault', 'reception_slash', 'rotation_fault', 'block_late_miss', 'attack_blocked'].includes(outcome)) return 'point_for_them';
  if (outcome === 'card_red') return 'card_red'; // Logic for red card point to be implemented if strict
  return 'neutral';
};

const rotateLineup = (lineup: MatchLineup): MatchLineup => {
  const nextPosMap: Record<number, CourtPosition> = {
    1: 6, 6: 5, 5: 4, 4: 3, 3: 2, 2: 1
  };
  const nextOnCourt = lineup.onCourt.map(slot => ({
    ...slot,
    position: nextPosMap[slot.position]
  }));
  return {
    ...lineup,
    onCourt: nextOnCourt,
    rotationIndex: lineup.rotationIndex + 1
  };
};

const substitutePlayer = (lineup: MatchLineup, inId: string, outId: string): MatchLineup => {
  // Check if player is on court
  const isOnCourt = lineup.onCourt.find(s => s.playerId === outId);
  if (!isOnCourt) return lineup;

  const newOnCourt = lineup.onCourt.map(s => s.playerId === outId ? { ...s, playerId: inId } : s);
  const newBench = lineup.benchPlayerIds.filter(id => id !== inId);
  newBench.push(outId);

  return {
    ...lineup,
    onCourt: newOnCourt,
    benchPlayerIds: newBench
  };
};

export const reconstructMatchState = (
  events: GameEvent[], 
  initialLineup: MatchLineup,
  matchIsHome: boolean // Used to guess initial serve if not specified
): MatchState => {

  // Sort by timestamp just in case
  const sortedEvents = [...events].sort((a, b) => a.timestamp - b.timestamp);

  // Initial State
  let state: MatchState = {
    currentSet: 1,
    teamPoints: 0,
    opponentPoints: 0,
    currentLineup: { ...initialLineup },
    servingSide: matchIsHome ? 'us' : 'them', // Default assumption: Home serves first set. 
    // In a real app, we'd have a SET_START event that defines who serves.
    lastEvent: null,
    hasRotatedInCurrentRun: false
  };

  // Process Event Stream
  for (const event of sortedEvents) {
    state.lastEvent = event;

    // 1. Handle Set Changes (Implicitly by setNumber in event, or explicit set_start)
    if (event.setNumber > state.currentSet) {
      // New Set started. Reset score.
      state.currentSet = event.setNumber;
      state.teamPoints = 0;
      state.opponentPoints = 0;
      state.hasRotatedInCurrentRun = false;

      // Toggle serve for next set (simple logic)
      // Set 1: Home(Us), Set 2: Them, Set 3: Us...
      // If event.eventType === 'set_start' we would read from that.
      const initialServer = (event.setNumber % 2 !== 0) === matchIsHome ? 'us' : 'them';
      state.servingSide = initialServer;
    }

    // 2. Handle Substitutions
    if (event.eventType === 'sub' && event.subInPlayerId && event.subOutPlayerId) {
      state.currentLineup = substitutePlayer(state.currentLineup, event.subInPlayerId, event.subOutPlayerId);
      continue;
    }

    // 3. Handle Game Events
    if (event.eventType === 'game' && event.outcome) {
      const impact = getImpact(event.outcome);

      if (impact === 'point_for_us') {
        state.teamPoints++;

        // ROTATION LOGIC:
        // We only rotate if we win a point AND we were NOT serving (Side-out).
        if (state.servingSide === 'them') {
          state.currentLineup = rotateLineup(state.currentLineup);
          state.servingSide = 'us';
          state.hasRotatedInCurrentRun = false; // Reset flag (though redundant with side change)
        } else {
          // We were serving and won point -> Keep serving, no rotate.
          state.servingSide = 'us';
        }
      } 
      else if (impact === 'point_for_them') {
        state.opponentPoints++;
        // We lose serve. They get point.
        state.servingSide = 'them';
        // They might rotate, but we don't track their rotation index visually usually, 
        // or we assume they rotate if we were serving.
      }
    }
  }

  return state;
};

