export const getTeamPlayers = async (teamId: string): Promise<Player[]> => {
  return new Promise(resolve => {
    const all = load<Player[]>(KEY_PLAYERS, []);
    setTimeout(() => resolve(all), 200);
  });
};

export const updatePlayer = async (updated: Player): Promise<Player> => {
  return new Promise(resolve => {
    const all = load<Player[]>(KEY_PLAYERS, []);
    const index = all.findIndex(p => p.id === updated.id);
    if (index >= 0) {
      all[index] = { ...all[index], ...updated };
    } else {
      all.push(updated);
    }
    save(KEY_PLAYERS, all);
    setTimeout(() => resolve(updated), 200);
  });
};

