export const getLeaderboard = async (filters: any): Promise<Player[]> => {
    return new Promise(resolve => {
        const players = load<Player[]>(KEY_PLAYERS, []);
        let sorted = [...players];

        if (filters.role && filters.role !== 'all') {
            sorted = sorted.filter(p => p.position === filters.role);
        }
        if (filters.region && filters.region !== 'all') {
            sorted = sorted.filter(p => p.region === filters.region);
        }

        sorted.sort((a, b) => b.averageRating - a.averageRating);
        setTimeout(() => resolve(sorted), 300);
    });
};

