        let evForMatch = allEvents.filter((ev) => ev.matchId === match.id && ev.playerId === playerId && ev.eventType === 'game');

        // --- DEMO FAKE DATA ---
        if (evForMatch.length === 0 && (match.id === 'm1' || match.id === 'm2') && playerId.startsWith('p')) {
             const isM1 = match.id === 'm1';
             result.push({
                 id: `fake_${match.id}`,
                 matchId: match.id,
                 playerId: playerId,
                 teamId: player.teamId,
                 matchDate: match.date,
                 opponentName: match.opponentName,
                 rating: isM1 ? 8.2 : 6.5,
                 breakdown: { attack: 0, serve: 0, reception: 0, block: 0, defense: 0 },
                 totalPoints: isM1 ? 15 : 8,
                 errors: isM1 ? 2 : 5,
                 totals: {
                     attacks: isM1 ? 20 : 15,
                     attackPoints: isM1 ? 10 : 5,
                     attackErrors: isM1 ? 2 : 4,
                     serves: 12,
                     aces: isM1 ? 3 : 1,
                     serveErrors: 2,
                     receptions: 25,
                     perfectReceptions: isM1 ? 15 : 8,
                     negativeReceptions: 2,
                     blocks: 5,
                     blockPoints: isM1 ? 2 : 1,
                     digs: 8
                 }
             });
             continue;
        }

        if (evForMatch.length === 0) continue;

        const ratingResult = computeVolleyRating(evForMatch, { role: player.position });

        let attacks = 0;
        let attackPoints = 0;
        let attackErrors = 0;
        let serves = 0;
        let aces = 0;
        let serveErrors = 0;
        let receptions = 0;
        let perfectReceptions = 0;
        let negativeReceptions = 0;
        let blocks = 0;
        let blockPoints = 0;
        let digs = 0;

        for (const ev of evForMatch) {
          if (ev.eventType !== 'game' || !ev.fundamental || !ev.outcome) continue;

          switch (ev.fundamental) {
            case Fundamental.ATTACK:
              attacks++;
              if (ev.outcome === 'attack_point' || ev.outcome === 'attack_tool') attackPoints++;
              if (ev.outcome === 'attack_error' || ev.outcome === 'attack_blocked') attackErrors++;
              break;
            case Fundamental.SERVE:
              serves++;
              if (ev.outcome === 'serve_ace') aces++;
              if (ev.outcome === 'serve_error') serveErrors++;
              break;
            case Fundamental.RECEPTION:
              receptions++;
              if (ev.outcome === 'reception_perfect') perfectReceptions++;
              if (ev.outcome === 'reception_negative' || ev.outcome === 'reception_ace_conceded' || ev.outcome === 'reception_slash') negativeReceptions++;
              break;
            case Fundamental.BLOCK:
              blocks++;
              if (ev.outcome === 'block_point') blockPoints++;
              break;
            case Fundamental.DEFENSE:
              if (ev.outcome === 'defense_great' || ev.outcome === 'defense_ok' || ev.outcome === 'defense_cover') digs++;
              break;
          }
        }

        result.push({
          id: `s_${match.id}_${playerId}`,
          matchId: match.id,
          playerId,
          teamId: player.teamId,
          matchDate: match.date,
          opponentName: match.opponentName,
          rating: ratingResult.rating,
          breakdown: ratingResult.breakdown,
          totalPoints: attackPoints + aces + blockPoints,
          errors: attackErrors + serveErrors, 
          totals: {
            attacks,
            attackPoints,
            attackErrors,
            serves,
            aces,
            serveErrors,
            receptions,
            perfectReceptions,
            negativeReceptions,
            blocks,
            blockPoints,
            digs,
          },
        });
      }

      setTimeout(() => resolve(result), 300);
  });
};

// --- LINEUP & EVENT RECORDING ---

export const getInitialLineupForMatch = async (matchId: string): Promise<MatchLineup | null> => {
    const lineups = load<MatchLineup[]>(KEY_LINEUPS, []);
    const stored = lineups.find(l => l.matchId === matchId);

    if (stored) return stored;

    const players = load<Player[]>(KEY_PLAYERS, []);
    const starters = players.slice(0, 6);
    const bench = players.slice(6);

    const newLineup: MatchLineup = {
        id: `l_${matchId}_init`,
        matchId: matchId,
        setNumber: 1,
        rotationIndex: 0,
        liberoId: bench.find(p => p.position === PlayerPosition.LIBERO)?.id,
        onCourt: starters.map((p, i) => ({ position: (i + 1) as CourtPosition, playerId: p.id })),
        benchPlayerIds: bench.map(p => p.id)
    };

    lineups.push(newLineup);
    save(KEY_LINEUPS, lineups);

    return newLineup;
};

// This is now purely for the "Initial" lineup. Subsequent lineups are derived from events.
export const updateLineup = async (lineup: MatchLineup): Promise<void> => {
    const lineups = load<MatchLineup[]>(KEY_LINEUPS, []);
    const index = lineups.findIndex(l => l.matchId === lineup.matchId);
    if (index >= 0) {
        lineups[index] = lineup;
    } else {
        lineups.push(lineup);
    }
    save(KEY_LINEUPS, lineups);
};

export const saveEvent = async (event: GameEvent): Promise<void> => {
    return new Promise((resolve) => {
        const events = load<GameEvent[]>(KEY_EVENTS, []);
        // Force UUID
        if (!event.id || event.id.length < 10) event.id = generateId();
        events.push(event);
        save(KEY_EVENTS, events);
        resolve();
    });
};

export const getEventsForMatch = async (matchId: string): Promise<GameEvent[]> => {
  return new Promise(resolve => {
    const events = load<GameEvent[]>(KEY_EVENTS, []);
    resolve(events.filter(e => e.matchId === matchId));
  });
};

export const deleteLastEvent = async (matchId: string): Promise<GameEvent | null> => {
    return new Promise((resolve) => {
        const events = load<GameEvent[]>(KEY_EVENTS, []);
        // Find last event for this match
        let lastIdx = -1;
        for(let i = events.length - 1; i >= 0; i--) {
            if (events[i].matchId === matchId) {
                lastIdx = i;
                break;
            }
        }

        if (lastIdx >= 0) {
            const removed = events.splice(lastIdx, 1)[0];
            save(KEY_EVENTS, events);
            resolve(removed);
        } else {
            resolve(null);
        }
    });
};

import React, { useState, useEffect, useMemo } from 'react';
