const load = <T>(key: string, defaultVal: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item) : defaultVal;
  } catch (e) {
    console.error(`Error loading ${key}`, e);
    return defaultVal;
  }
};

const save = <T>(key: string, data: T) => {
  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (e) {
    console.error(`Error saving ${key}`, e);
  }
};

if (!localStorage.getItem(KEY_INIT)) {
  save(KEY_PLAYERS, SEED_PLAYERS);
  save(KEY_MATCHES, SEED_MATCHES);
  save(KEY_LINEUPS, []);
  localStorage.setItem(KEY_INIT, 'true');
}

// --- PLAYER SERVICES ---
export const getTeamPlayers = async (teamId: string): Promise<Player[]> => {
  return new Promise(resolve => {
    const all = load<Player[]>(KEY_PLAYERS, []);
    setTimeout(() => resolve(all), 200);
  });
};

export const updatePlayer = async (updated: Player): Promise<Player> => {
  return new Promise(resolve => {
    const all = load<Player[]>(KEY_PLAYERS, []);
    const index = all.findIndex(p => p.id === updated.id);
    if (index >= 0) {
      all[index] = { ...all[index], ...updated };
    } else {
      all.push(updated);
    }
    save(KEY_PLAYERS, all);
    setTimeout(() => resolve(updated), 200);
  });
};

export const createPlayer = async (newPlayer: Omit<Player, 'id' | 'averageRating' | 'matchesPlayed'>): Promise<Player> => {
    return new Promise(resolve => {
        const all = load<Player[]>(KEY_PLAYERS, []);
        const player: Player = {
            ...newPlayer,
            id: generateId(),
            averageRating: 6.0,
            matchesPlayed: 0,
            trend: 'stable'
        };
        all.push(player);
        save(KEY_PLAYERS, all);
        setTimeout(() => resolve(player), 200);
    });
};

// --- MATCH SERVICES ---
export const getMatches = async (teamId: string): Promise<Match[]> => {
  return new Promise(resolve => {
    const all = load<Match[]>(KEY_MATCHES, []);
    all.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setTimeout(() => resolve(all), 200);
  });
};

export const createMatch = async (matchData: Omit<Match, 'id' | 'status'>): Promise<Match> => {
    return new Promise(resolve => {
        const all = load<Match[]>(KEY_MATCHES, []);
        const newMatch: Match = {
            ...matchData,
            id: generateId(),
            status: 'scheduled'
        };
        all.unshift(newMatch); 
        save(KEY_MATCHES, all);
        setTimeout(() => resolve(newMatch), 200);
    });
};

export const getPlayerMatches = async (playerId: string): Promise<Match[]> => {
    const matches = load<Match[]>(KEY_MATCHES, []);
    // Logic to check participation could be added here by checking event logs
    return matches.filter(m => m.status === 'completed');
};

// --- STATS SERVICES ---
export const getLeaderboard = async (filters: any): Promise<Player[]> => {
    return new Promise(resolve => {
        const players = load<Player[]>(KEY_PLAYERS, []);
        let sorted = [...players];
        if (filters.role && filters.role !== 'all') sorted = sorted.filter(p => p.position === filters.role);
        if (filters.region && filters.region !== 'all') sorted = sorted.filter(p => p.region === filters.region);
        sorted.sort((a, b) => b.averageRating - a.averageRating);
        setTimeout(() => resolve(sorted), 300);
    });
};

export const getPlayerMatchStatsForPlayer = async (playerId: string): Promise<PlayerMatchStats[]> => {
  return new Promise(async (resolve) => {
      const result: PlayerMatchStats[] = [];
      const players = load<Player[]>(KEY_PLAYERS, []);
      const player = players.find((p) => p.id === playerId);
      if (!player) { resolve([]); return; }
      const allMatches = load<Match[]>(KEY_MATCHES, []);

      for (const match of allMatches) {
        // Retrieve events using the new store
        const evForMatch = eventStore.getEvents(match.id).filter(ev => ev.playerId === playerId && ev.eventType === 'game');

        if (evForMatch.length === 0) continue;

        const ratingResult = computeVolleyRating(evForMatch, { role: player.position });
        let attacks = 0, attackPoints = 0, attackErrors = 0;
        let serves = 0, aces = 0, serveErrors = 0;
        let receptions = 0, perfectReceptions = 0, negativeReceptions = 0;
        let blocks = 0, blockPoints = 0, digs = 0;

        for (const ev of evForMatch) {
          if (!ev.fundamental || !ev.outcome) continue;
          switch (ev.fundamental) {
            case Fundamental.ATTACK:
              attacks++;
              if (ev.outcome === 'attack_point' || ev.outcome === 'attack_tool') attackPoints++;
              if (ev.outcome === 'attack_error' || ev.outcome === 'attack_blocked') attackErrors++;
              break;
            case Fundamental.SERVE:
              serves++;
              if (ev.outcome === 'serve_ace') aces++;
              if (ev.outcome === 'serve_error') serveErrors++;
              break;
            case Fundamental.RECEPTION:
              receptions++;
              if (ev.outcome === 'reception_perfect') perfectReceptions++;
              if (ev.outcome === 'reception_negative' || ev.outcome === 'reception_ace_conceded' || ev.outcome === 'reception_slash') negativeReceptions++;
              break;
            case Fundamental.BLOCK:
              blocks++;
              if (ev.outcome === 'block_point') blockPoints++;
              break;
            case Fundamental.DEFENSE:
              if (ev.outcome === 'defense_great' || ev.outcome === 'defense_ok' || ev.outcome === 'defense_cover') digs++;
              break;
          }
        }

        result.push({
          id: `s_${match.id}_${playerId}`,
          matchId: match.id,
          playerId,
          teamId: player.teamId,
          rating: ratingResult.rating,
          breakdown: ratingResult.breakdown,
          totalPoints: attackPoints + aces + blockPoints,
          errors: attackErrors + serveErrors,
          matchDate: match.date,
          opponentName: match.opponentName, 
          totals: {
            attacks, attackPoints, attackErrors,
            serves, aces, serveErrors,
            receptions, perfectReceptions, negativeReceptions,
            blocks, blockPoints, digs,
          },
        });
      }
      setTimeout(() => resolve(result), 300);
  });
};

// --- LINEUP INIT (Still used for initial setup, subsequent states derived from events) ---
export const getInitialLineupForMatch = async (matchId: string): Promise<MatchLineup | null> => {
    const lineups = load<MatchLineup[]>(KEY_LINEUPS, []);
    const stored = lineups.find(l => l.matchId === matchId);

    if (stored) return stored;

    const players = load<Player[]>(KEY_PLAYERS, []);
    const starters = players.slice(0, 6);
    const bench = players.slice(6);

    const newLineup: MatchLineup = {
        id: `l_${matchId}_init`,
        matchId: matchId,
        setNumber: 1,
        rotationIndex: 0,
        liberoId: bench.find(p => p.position === PlayerPosition.LIBERO)?.id,
        onCourt: starters.map((p, i) => ({ position: (i + 1) as CourtPosition, playerId: p.id })),
        benchPlayerIds: bench.map(p => p.id)
    };

    lineups.push(newLineup);
    save(KEY_LINEUPS, lineups);

    return newLineup;
};

